async (page) => {
  // Check error messages on the login screen
  const errorText = await page.evaluate(() => {
    const errEl = document.querySelector('.login-error') || document.querySelector('[class*="error"]') || document.querySelector('#login-error');
    return errEl ? errEl.textContent : 'no error element found';
  });

  // Also get all visible text on page
  const allText = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('p, span, div')).map(el => el.textContent.trim()).filter(t => t.length > 5 && t.length < 200).slice(0, 20);
  });

  return { errorText, allText };
}
